def keep_features_dicts_synced(func):
    """
    Wrapper to keep the secondary dictionary, `_column_requires_decoding`, of the `Features` class synced
    with the main dictionary `Features`, on all operations that modify the latter.
    """

    @wraps(func)
    def wrapper(*args, **kwargs):
        if args:
            self: "Features" = args[0]
            args = args[1:]
        else:
            self: "Features" = kwargs.pop("self")
        out = func(self, *args, **kwargs)
        assert hasattr(self, "_column_requires_decoding")
        self._column_requires_decoding = {col: require_decoding(feature) for col, feature in self.items()}
        return out

    wrapper.__name__ = func.__name__
    return wrapper


def _deep_merge_dicts(old: dict, new: dict) -> dict:
    """Recursively merge ``new`` into ``old`` in place, merging nested dicts and overwriting other values."""
    for key, value in new.items():
        if key in old and isinstance(old[key], dict) and isinstance(value, dict):
            _deep_merge_dicts(old[key], value)
        else:
            old[key] = value
    return old


